mapper.select:
SELECT t.*, u.nickname as authorName, u.avatar_path as avatar_path, u.avatar_path as authorAvatar, b.name as boardName FROM forum_thread t LEFT JOIN forum_user_profile u ON t.user_id = u.user_id LEFT JOIN forum_board b ON t.board_id = b.id WHERE t.board_id = #{boardId} AND t.status = 1
AND (t.title LIKE CONCAT('%', #{keyword}, '%') OR t.content LIKE CONCAT('%', #{keyword}, '%'))
AND t.thread_type = #{threadType}
AND EXISTS ( SELECT 1 FROM forum_thread_tag tt JOIN forum_tag tag ON tag.id = tt.tag_id WHERE tt.thread_id = t.id AND tag.normalized_name = #{normalizedTagName} )
ORDER BY t.is_top DESC, t.last_reply_time DESC LIMIT #{offset}, #{size}

SELECT t.*, u.nickname as authorName, u.avatar as avatar_path, u.avatar as authorAvatar, b.name as boardName FROM forum_thread t LEFT JOIN forum_user_profile u ON t.user_id = u.user_id LEFT JOIN forum_board b ON t.board_id = b.id WHERE t.board_id = #{boardId} AND t.status = 1
AND (t.title LIKE CONCAT('%', #{keyword}, '%') OR t.content LIKE CONCAT('%', #{keyword}, '%'))
AND t.thread_type = #{threadType}
AND EXISTS ( SELECT 1 FROM forum_thread_tag tt JOIN forum_tag tag ON tag.id = tt.tag_id WHERE tt.thread_id = t.id AND tag.normalized_name = #{normalizedTagName} )
ORDER BY t.is_top DESC, t.last_reply_time DESC LIMIT #{offset}, #{size}

SELECT COUNT(*)
FROM forum_thread t
WHERE t.board_id = #{boardId}
  AND t.status = 1

    AND (t.title LIKE CONCAT('%', #{keyword}, '%') OR t.content LIKE CONCAT('%', #{keyword}, '%'))


    AND t.thread_type = #{threadType}


    AND EXISTS (
        SELECT 1
        FROM forum_thread_tag tt
        JOIN forum_tag tag ON tag.id = tt.tag_id
        WHERE tt.thread_id = t.id
          AND tag.normalized_name = #{normalizedTagName}
    )

